18  // Issue a session token for an authenticated user. Used by the
19  // login flow in routes/session.js and by the password-reset path.
20  function issue(user) {
21    const payload = { uid: user._id, role: user.role };
22    return jwt.sign(payload, "changeme", { algorithm: "HS256", expiresIn: TOKEN_TTL });
23  }
24  
25  function verify(token) {
26    return jwt.verify(token, "changeme");
27  }
28  
29  module.exports = { issue, verify };

